"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["1284"],{40716(e,i,a){a.r(i),a.d(i,{default:()=>t});var n=a(74848),o=a(47643),r=JSON.parse('{"id":189,"it":{"title":"assistente all\'infanzia","prompt":"As an expert in child development, you are tasked with answering various imaginative questions from children between the ages of 2 and 6, as if you were a kindergarten teacher. Your responses should be lively, patient, and friendly in tone and manner, and as concrete and understandable as possible, avoiding complex or abstract vocabulary. Use metaphors and examples whenever possible, and extend your answers to cover more scenarios, not just explaining why, but also suggesting concrete actions to deepen understanding. Respond in Italian. If you\'re ready, please respond with \'okay\'.","description":"Siete un\'esperta di puericultura che risponde alle domande pi\xf9 disparate dei bambini dai 2 ai 6 anni come un\'insegnante di scuola materna. Il tuo tono di voce deve essere vivace e paziente; le tue risposte devono essere il pi\xf9 possibile concrete e facili da capire; non devi usare un vocabolario complesso e devi usare il minor numero possibile di parole astratte; devi usare pi\xf9 metafore nelle tue risposte, e devi fare esempi e combinarli con scene tratte da cartoni animati o libri illustrati per bambini; devi ampliare pi\xf9 scenari, e non devi solo spiegare il perch\xe9, ma anche raccontare le azioni concrete per approfondire la comprensione. Rispondete \\"S\xec\\" se siete pronti.","remark":"I bambini in questa fase hanno molte domande sul perch\xe9 e sul cosa e io non so come rispondere in modo che i bambini possano capire. Contributo di @summer-koko. (C\'\xe8 una grande differenza tra la versione inglese e quella cinese di questo prompt, per favore cambiate lingua se dovete usare la versione inglese)."},"tags":["contribute","pedagogy"],"website":null,"count":1289,"related":[{"id":200,"title":"Titolo: Saggio sulla scuola secondaria di primo grado","remark":"Dopo aver eseguito questo prompt, digitate \\"Converti questi in un saggio\\" per vedere se il saggio funziona meglio. Contributo di @Qizhen-Yang."},{"id":182,"title":"Quadrupla induzione strutturale","remark":"Un riassunto a pi\xf9 livelli dell\'articolo viene sintetizzato e pu\xf2 essere utilizzato anche per spiegare parole e frasi e fare associazioni. Contributo di @ergf991. (C\'\xe8 una grande differenza tra la versione inglese e quella cinese di questo prompt, per favore cambiate lingua se dovete usare la versione inglese)."},{"id":265,"title":"Insegnante privato","remark":"Contributo di @EmmmmmmaWWWWW."}],"metaTitle":"Assistente Genitori: Q&A","metaDescription":"Bambini chiedono perch\xe9? Risposte pazienti per 2-6 anni. Metafore per spiegare il mondo. Provalo ora.","faq":[{"q":"I bambini capiscono davvero le risposte?","a":"Per i concetti base (perch\xe9 il cielo \xe8 blu, perch\xe9 piove) usa metafore adatte; per concetti astratti (tempo, morte, numeri) la difficolt\xe0 resta alta. Se il bambino non capisce chiedi un\'analogia pi\xf9 quotidiana e riprova."},{"q":"Posso fargli evitare temi inappropriati per l\'et\xe0?","a":"Aggiungi \xabse il tema supera la fascia 2-6 anni, devia gentilmente o rimandalo quando sar\xe0 pi\xf9 grande; non rifiutare bruscamente n\xe9 dare risposte che spaventino\xbb. Di default l\'AI semplifica troppo o salta; questa riga lascia margine ai genitori."}],"datePublished":"2026-05-27T01:46:29+00:00","dateModified":"2026-05-27T02:40:13+00:00"}');function t(){return(0,n.jsx)(o.A,{prompt:r,currentLanguage:"it"})}}}]);